(80, 'PRENDRE SOI DE SOI ET PREVENIR L\'EPUISEMENT PROFESSIONNEL 2021', 'DECEMBRE 2021', '', 'IIPERIA', 1, 'MANDATAIRE'),
(81, 'MIEUX COMPRENDRE LES STEREOTYPES DE GENRE POUR RENFORCER L\'EGALITE FILLE-GARCON 14H (2023)', 'MARS 2023', 'Objectifs :\r\nEtre en mesure de renforcer l’égalité des filles et des garçons dès le plus jeune âge en luttant contre les\r\nstéréotypes de genre dans ses pratiques quotidiennes ;\r\nPublic : Tous salariés et assistants maternels du particulier employeur.\r\nPrérequis : Aucun\r\nDurée : 14 heures\r\nDates : Les Samedis 4 et 11 Mars 2023 – 9h/12h30-13h30/17h\r\nLieu : RENNES\r\n', 'IIPERIA', 1, 'MANDATAIRE'),
(82, 'Comprendre les émotions pour mieux accompagner l’enfant au quotidien', '2022 JUIN', 'Comprendre les émotions pour mieux accompagner l’enfant au quotidien BAIN DE BRETAGNE 11 ET 18 JUIN (14h)', 'IPERIA', 1, 'MANDATAIRE'),
(83, 'Préparation du certificat sauveteur secouriste du travail (SST)', '2022 OCTOBRE', 'Préparation du certificat sauveteur secouriste du travail (SST) » - Rennes – les 12 et 19 octobre 2022 (14h)', 'IPERIA', 1, 'MANDATAIRE'),
